import { Platform } from 'react-native'

export type LlamaRuntimeProfile = 'device' | 'simulator'

const requestedLlamaProfile = process.env.EXPO_PUBLIC_LLAMA_PROFILE
export const LLAMA_RUNTIME_PROFILE: LlamaRuntimeProfile =
  requestedLlamaProfile === 'simulator' ? 'simulator' : 'device'

const isSimulatorProfile = LLAMA_RUNTIME_PROFILE === 'simulator'
const enabledEnvValues = new Set(['enabled', 'true', '1', 'yes', 'on'])
const disabledEnvValues = new Set(['disabled', 'false', '0', 'no', 'off'])

const envFlag = (value: string | undefined, fallback: boolean): boolean => {
  const normalised = value?.trim().toLowerCase()
  if (normalised === undefined || normalised === '') return fallback
  if (enabledEnvValues.has(normalised)) return true
  if (disabledEnvValues.has(normalised)) return false
  return fallback
}

const simulatorVisionEnabled = envFlag(process.env.EXPO_PUBLIC_SIMULATOR_VISION, true)
const simulatorMultimodalGpuEnabled = envFlag(process.env.EXPO_PUBLIC_SIMULATOR_MULTIMODAL_GPU, false)

export const INFERENCE_CONFIG = {
  PROFILE: LLAMA_RUNTIME_PROFILE,
  N_CTX: isSimulatorProfile ? 2048 : 4096,
  N_PREDICT_MAX: isSimulatorProfile ? 256 : 512,
  N_BATCH: 512,
  N_UBATCH: 512,
  N_THREADS: Platform.OS === 'ios' ? (isSimulatorProfile ? 4 : 6) : 4,
  N_GPU_LAYERS: 99,
  N_PARALLEL: 1,
  IMAGE_MAX_TOKENS: isSimulatorProfile ? 256 : 512,
  MULTIMODAL_GENERATION_ENABLED: !isSimulatorProfile || simulatorVisionEnabled,
  MULTIMODAL_USE_GPU: !isSimulatorProfile || simulatorMultimodalGpuEnabled,
  THINKING_BUDGET_TOKENS: isSimulatorProfile ? 32 : 64,
  THINKING_BUDGET_MESSAGE: '\n\nThinking budget reached; answer now.',
  CTX_SHIFT: false as const,
  FLASH_ATTN_TYPE: 'auto' as const,
} as const

export const GEMMA_STOPS = [
  '<end_of_turn>',
  '<|end_of_turn|>',
  '<|eot_id|>',
  '<|im_end|>',
  '<|endoftext|>',
] as const

export const TOOL_LIMITS = {
  MAX_ROUNDS: 3,
} as const

export const MEMORY_PRECONTEXT = {
  TOP_K: 3,
  SNIPPET_MAX_CHARS: 420,
} as const

export const STREAMING = {
  // Hard cap chunk size so a single rAF flush can't dominate a frame
  MAX_CHUNK_PER_FLUSH: 2048,
} as const

export const ROUTING = {
  FASTINO_TIMEOUT_MS: 250,
  CONFIDENCE_BUMP_THRESHOLD: 0.6,
} as const

export const BRAIN_ID = 'jeff'

export const SYSTEM_PROMPT = [
  'You are Jeff, Alex Jay\'s private on-device brain.',
  'Be direct, useful, and concise.',
  'Keep reasoning in the hidden thinking channel only.',
  'Visible answers must not contain thought tags, channel markers, or scratchpad text.',
  'You have private memory tools. Use them proactively and only when useful.',
  'Before answering questions about Alex, his family, preferences, personal facts, plans, projects, or past instructions, call memory_recall with a concise natural-language query.',
  'Do not answer personal-memory questions from generic model knowledge. If memory_recall returns no relevant result, say you do not have that stored yet.',
  'When the user gives a stable personal fact, preference, relationship, plan, project detail, or explicit feedback that would help in future chats, call memory_remember.',
  'Never save greetings, one-off small talk, temporary state, or facts that will not matter later.',
  'Use memory_list and memory_forget only when the user asks to inspect or delete memories.',
  'Never claim private data left the phone unless the selected provider is cloud.',
].join('\n')

import { createId } from '../../lib/id'
import { routerService } from '../../services/router'
import type { ContentPart, GenerationStatus, Message, RouteDecision, Slice, ToolCall } from '../types'

const ACTIVE_GENERATION_STATUSES: readonly GenerationStatus[] = [
  'routing',
  'preparing-vision',
  'loading-first-token',
  'thinking',
  'using-tools',
  'streaming',
]

export type SendUserMessageInput = {
  readonly text?: string
  readonly attachments?: readonly ContentPart[]
}

export type CommitStreamingMessageInput = {
  readonly content?: string
  readonly thinking?: string
}

export type ChatSlice = {
  threadId: string
  messages: Message[]
  draft: string
  stagedAttachments: ContentPart[]
  setDraft: (draft: string) => void
  stageAttachment: (part: ContentPart) => void
  removeStagedAttachment: (index: number) => void
  clearStaged: () => void
  sendUserMessage: (input?: SendUserMessageInput) => Promise<void>
  beginAssistantMessage: (id: string, routeDecision?: RouteDecision) => void
  appendStreamingChunk: (id: string, chunk: string) => void
  appendThinkingChunk: (id: string, chunk: string) => void
  markThinkingDone: (id: string) => void
  commitStreamingMessage: (id: string, final?: CommitStreamingMessageInput) => void
  appendToolCall: (id: string, toolCall: ToolCall) => void
  startNewThread: () => void
  clearMessages: () => void
}

export const createChatSlice: Slice<ChatSlice> = (set, get) => ({
  threadId: createId('thread'),
  messages: [],
  draft: '',
  stagedAttachments: [],

  setDraft: (draft) => set({ draft }, false, 'chat/setDraft'),
  stageAttachment: (part) =>
    set((s) => ({ stagedAttachments: [...s.stagedAttachments, part] }), false, 'chat/stageAttachment'),
  removeStagedAttachment: (index) =>
    set((s) => ({
      stagedAttachments: s.stagedAttachments.filter((_, stagedIndex) => stagedIndex !== index),
    }), false, 'chat/removeStagedAttachment'),
  clearStaged: () => set({ stagedAttachments: [] }, false, 'chat/clearStaged'),

  sendUserMessage: async (input) => {
    const state = get()
    if (ACTIVE_GENERATION_STATUSES.includes(state.generationStatus)) return

    const text = (input?.text ?? state.draft).trim()
    const attachments = [...(input?.attachments ?? state.stagedAttachments)]
    const parts: ContentPart[] = [
      ...(text === '' ? [] : [{ type: 'text' as const, text }]),
      ...attachments,
    ]
    if (parts.length === 0) return

    const abortController = new AbortController()
    get()._setGenerationStatus('routing')
    get()._setAbortController(abortController)

    const userMessage: Message = {
      id: createId('user'),
      role: 'user',
      parts,
      createdAt: Date.now(),
    }

    set((s) => ({
      messages: [...s.messages, userMessage],
      draft: '',
      stagedAttachments: [],
    }), false, 'chat/sendUserMessage')

    const routingText = text === '' && attachments.length > 0
      ? 'Message with media attachment'
      : text
    const history = state.messages
      .slice(-6)
      .map((message) => message.parts
        .filter((part): part is Extract<ContentPart, { type: 'text' }> => part.type === 'text')
        .map((part) => `${message.role}: ${part.text}`)
      .join('\n'))
      .filter((line) => line.trim() !== '')

    try {
      const routeDecision = state.providerMode === 'smart'
        ? await routerService.classify(routingText, history, state.manualProvider)
        : routerService.manual(state.manualProvider)

      if (abortController.signal.aborted) {
        get()._setGenerationStatus('idle')
        return
      }

      get().setLastDecision(routeDecision)

      const assistantMessageId = createId('assistant')
      get().beginAssistantMessage(assistantMessageId, routeDecision)

      const { inferenceService } = await import('../../services/inference')
      await inferenceService.generate({
        messageId: assistantMessageId,
        provider: routeDecision.provider,
        signal: abortController.signal,
      })
    } catch (error) {
      if (abortController.signal.aborted) {
        get()._setGenerationStatus('idle')
        return
      }
      get()._setGenerationStatus('error')
      throw error
    } finally {
      get()._setAbortController(null)
    }
  },

  beginAssistantMessage: (id, routeDecision) =>
    set((s) => ({
      messages: [
        ...s.messages,
        {
          id,
          role: 'assistant',
          parts: [],
          routeDecision,
          createdAt: Date.now(),
          streamingText: '',
          thinking: { text: '', status: 'streaming' },
        },
      ],
    }), false, 'chat/beginAssistantMessage'),

  appendStreamingChunk: (id, chunk) =>
    set((s) => {
      return {
        messages: s.messages.map((message) =>
          message.id === id
            ? { ...message, streamingText: (message.streamingText ?? '') + chunk }
            : message,
        ),
      }
    }, false, 'chat/appendStreamingChunk'),

  appendThinkingChunk: (id, chunk) => {
    if (chunk === '') return

    set((s) => {
      return {
        messages: s.messages.map((message) => {
          if (message.id !== id) return message
          const thinking = message.thinking ?? { text: '', status: 'streaming' as const }
          return {
            ...message,
            thinking: {
              text: thinking.text + chunk,
              status: 'streaming',
            },
          }
        }),
      }
    }, false, 'chat/appendThinkingChunk')
  },

  markThinkingDone: (id) =>
    set((s) => {
      return {
        messages: s.messages.map((message) => {
          if (message.id !== id) return message
          const thinking = message.thinking ?? { text: '', status: 'streaming' as const }
          return {
            ...message,
            thinking: {
              ...thinking,
              status: 'done',
            },
          }
        }),
      }
    }, false, 'chat/markThinkingDone'),

  commitStreamingMessage: (id, final) =>
    set((s) => {
      return {
        messages: s.messages.map((message) => {
          if (message.id !== id) return message
          const finalContent = final?.content?.trim()
          const text = finalContent === undefined || finalContent === ''
            ? message.streamingText ?? ''
            : finalContent
          const parts = text === '' ? message.parts : [{ type: 'text' as const, text }]
          const finalThinking = final?.thinking?.trim()
          const thinking = message.thinking === undefined
            ? undefined
            : {
                text: finalThinking === undefined || finalThinking === ''
                  ? message.thinking.text
                  : finalThinking,
                status: 'done' as const,
              }
          return { ...message, parts, thinking, streamingText: undefined }
        }),
      }
    }, false, 'chat/commitStreamingMessage'),

  appendToolCall: (id, toolCall) =>
    set((s) => {
      return {
        messages: s.messages.map((message) => {
          if (message.id !== id) return message
          const toolCalls = message.toolCalls ?? []
          const existingIndex = toolCalls.findIndex((existing) => existing.id === toolCall.id)
          if (existingIndex === -1) return { ...message, toolCalls: [...toolCalls, toolCall] }

          return {
            ...message,
            toolCalls: toolCalls.map((existing, index) => index === existingIndex ? toolCall : existing),
          }
        }),
      }
    }, false, 'chat/appendToolCall'),

  startNewThread: () =>
    set({
      threadId: createId('thread'),
      messages: [],
      draft: '',
      stagedAttachments: [],
    }, false, 'chat/startNewThread'),
  clearMessages: () =>
    set({
      threadId: createId('thread'),
      messages: [],
      draft: '',
      stagedAttachments: [],
    }, false, 'chat/clearMessages'),
})

import { useShallow } from 'zustand/react/shallow'

import { useStore } from './index'

export const useMessageIds = () => useStore(useShallow((s) => s.messages.map((m) => m.id)))

export const useMessage = (id: string) => useStore((s) => s.messages.find((m) => m.id === id))

export const useStreamingText = (id: string) =>
  useStore((s) => s.messages.find((m) => m.id === id)?.streamingText ?? '')

export const useGenerationStatus = () => useStore((s) => s.generationStatus)

export const useDraftAndAttachments = () =>
  useStore(useShallow((s) => ({ draft: s.draft, attachments: s.stagedAttachments })))

export const useSettings = () =>
  useStore(useShallow((s) => ({
    modelSize: s.modelSize,
    voiceEnabled: s.voiceEnabled,
    rememberConversation: s.rememberConversation,
    providerMode: s.providerMode,
    manualProvider: s.manualProvider,
    devMode: s.devMode,
  })))

export const useLastRouteDecision = () => useStore((s) => s.lastDecision)

export const useHasHydrated = () => useStore.persist.hasHydrated()

